import logging
import os
from typing import Optional
from azure.storage.blob import BlobServiceClient
from azure.core.exceptions import ResourceNotFoundError, UnauthorizedError
from azure.functions import HttpRequest, HttpResponse

def main(req: HttpRequest) -> HttpResponse:
    try:
        # Get blob path from query parameters
        blob_path = req.params.get('path')
        
        if not blob_path:
            return HttpResponse(
                "Blob path is required",
                status_code=400
            )
        
        # Validate blob path to prevent directory traversal
        if '..' in blob_path or blob_path.startswith('/'):
            return HttpResponse(
                "Invalid blob path",
                status_code=400
            )
        
        # Get connection string from environment variable
        connection_string = os.environ.get('AZURE_STORAGE_CONNECTION_STRING')
        if not connection_string:
            return HttpResponse(
                "Storage connection string not configured",
                status_code=500
            )
        
        # Initialize blob service client
        blob_service_client = BlobServiceClient.from_connection_string(connection_string)
        
        # Extract container name and blob name from path
        # Assuming path format: "container/blob_path"
        parts = blob_path.split('/', 1)
        if len(parts) != 2:
            return HttpResponse(
                "Invalid blob path format. Expected: container/blob_path",
                status_code=400
            )
        
        container_name = parts[0]
        blob_name = parts[1]
        
        # Get blob client
        blob_client = blob_service_client.get_blob_client(
            container=container_name,
            blob=blob_name
        )
        
        # Read blob content
        try:
            blob_data = blob_client.download_blob().readall()
        except ResourceNotFoundError:
            return HttpResponse(
                "Blob not found",
                status_code=404
            )
        except UnauthorizedError:
            return HttpResponse(
                "Access denied",
                status_code=403
            )
        
        # Get content type from blob metadata or default to binary
        content_type = blob_client.get_blob_properties().content_settings.content_type if hasattr(blob_client.get_blob_properties(), 'content_settings') else 'application/octet-stream'
        
        return HttpResponse(
            body=blob_data,
            status_code=200,
            headers={
                'Content-Type': content_type,
                'Cache-Control': 'public, max-age=3600'
            }
        )
        
    except Exception as e:
        logging.error(f"Error reading blob: {str(e)}")
        return HttpResponse(
            "Internal server error",
            status_code=500
        )